# --- API Base URL ---
BASE_URL = f'http://{RABBITMQ_HOST}:{RABBITMQ_API_PORT}/api'

# --- Helper function for API requests ---
def rabbitmq_api_request(method, endpoint, auth, data=None):
    url = f'{BASE_URL}{endpoint}'
    headers = {'Content-Type': 'application/json'}
    try:
        if method == 'GET':
            response = requests.get(url, auth=auth)
        elif method == 'PUT':
            response = requests.put(url, auth=auth, headers=headers, data=json.dumps(data))
        elif method == 'POST':
            response = requests.post(url, auth=auth, headers=headers, data=json.dumps(data))
        elif method == 'DELETE':
            response = requests.delete(url, auth=auth)
        else:
            raise ValueError(f"Unsupported HTTP method: {method}")

        response.raise_for_status() # Raise an HTTPError for bad responses (4xx or 5xx)
        return response
    except requests.exceptions.HTTPError as e:
        print(f"HTTP error for {method} {url}: {e.response.status_code} - {e.response.text}")
    except requests.exceptions.ConnectionError as e:
        print(f"Connection error to {url}: {e}")
    except Exception as e:
        print(f"An unexpected error occurred for {method} {url}: {e}")
    return None

# --- Main Script ---
if __name__ == '__main__':
    admin_auth = (RABBITMQ_API_USER, RABBITMQ_API_PASSWORD)

    print("Starting RabbitMQ configuration script...")

    for vhost_config in VHOST_CONFIGS:
        vhost_name = vhost_config['vhost_name']
        print(f"\n--- Processing Virtual Host: {vhost_name} ---")

        # 1. Create Virtual Host
        print(f"Creating vhost '{vhost_name}'...")
        response = rabbitmq_api_request('PUT', f'/vhosts/{vhost_name}', admin_auth, {'description': vhost_config['description']})
        if response and response.status_code in [201, 204]:
            print(f"Vhost '{vhost_name}' created or already exists.")
        elif response is None:
            print(f"Failed to create vhost '{vhost_name}'. Skipping configuration for this vhost.")
            continue # Skip to the next vhost if creation failed

        for user_data in vhost_config['users']:
            username = user_data['username']
            password = user_data['password']
            tags = user_data['tags']
            permissions = user_data['permissions']

            # 2. Create User
            print(f"Creating user '{username}'...")
            user_payload = {
                'password': password,
                'tags': ','.join(tags)
            }
            response = rabbitmq_api_request('PUT', f'/users/{username}', admin_auth, user_payload)
            if response and response.status_code in [201, 204]:
                print(f"User '{username}' created or already exists.")
            else:
                print(f"Failed to create user '{username}'. Skipping permissions for this user.")
                continue # Skip to the next user if creation failed

            # 3. Set Permissions for User on Vhost
            print(f"Setting permissions for user '{username}' on vhost '{vhost_name}'...")
            permissions_payload = {
                'configure': permissions.get('configure', ''),
                'write': permissions.get('write', ''),
                'read': permissions.get('read', '')
            }
            response = rabbitmq_api_request('PUT', f'/permissions/{vhost_name}/{username}', admin_auth, permissions_payload)
            if response and response.status_code in [201, 204]:
                print(f"Permissions set for user '{username}' on vhost '{vhost_name}'.")
            else:
                print(f"Failed to set permissions for user '{username}' on vhost '{vhost_name}'.")

    print("\nRabbitMQ configuration script finished.")